/// <summary>
/// calling etgIssueReceive()
/// </summary>
/// <returns>boolean.</returns>
public boolean validateWrite()
{
    boolean ret = next validateWrite();
    ret         = ret && this.etgIssueReceiveUpdate();
    ret         = ret && this.checkFDQty();
    ret         = ret && this.checkFDTotalQty();
    return ret;
}

public boolean checkFDQty()
{
    boolean isValid = true;

    if(ETGACFParameters::find().EnablefinancialdimensionVertical == NoYes::Yes)
    {
        InventJournalName inventJournalName = InventJournalName::find(this.inventJournalTable().JournalNameId);
        if(inventJournalName && inventJournalName.ETGTransferJournalFDChange == NoYes::Yes)
        {
            VendInvoiceTrans vendInvoiceTrans;

            select firstonly Qty from vendInvoiceTrans
                where vendInvoiceTrans.InventTransId == this.ETGTransferJournalInvoicetransid
                && vendInvoiceTrans.DataAreaId == this.DataAreaId;

            if(abs(this.Qty) > abs(vendInvoiceTrans.Qty))
            {
                isValid = checkFailed(strFmt("Transfer qauntity %1 can not be greater than invoice quantity %2", abs(this.Qty), vendInvoiceTrans.Qty));
            }
        }
    }

    return isValid;
}

