/// <summary>
/// When fields are modified related logic will be performed
/// </summary>
/// <param name = "_fieldId">FieldId</param>
public void modifiedField(FieldId _fieldId)
{
    next modifiedField(_fieldId);

    switch (_fieldId)
    {
        case fieldNum(InventJournalTrans, ETGIssueReceive):
            this.etgQtyValidation();
            break;

        case fieldNum(InventJournalTrans, ItemId):
            this.etgUOMValues();
            break;

        case fieldNum(InventJournalTrans, Qty):
            this.etgUOMValues();
            this.etgQtyValidation();
            break;
    }


}

/// <summary>
/// This is a new method created for getting the values for
/// Alternate UOM and Alternate quantity fields based on UnitConversion
/// </summary>
public void etgUOMValues()
{
    if(SalesParameters::find().ETGEnableCylinderTracking)
    {
        InventJournalTable  inventJournalTable = InventJournalTable::find(this.JournalId);
        InventJournalName   inventJournalName  = InventJournalName::find(inventJournalTable.JournalNameId);
        if(inventJournalName.ETGManualAdditionorDeletion == NoYes::Yes)
        {
            UnitOfMeasureConversion  unitOfMeasureConversion;
            InventTable              inventTable    = InventTable::find(this.ItemId);
            UnitOfMeasureRecId       fromUnitId     = UnitOfMeasure::unitOfMeasureIdBySymbol(inventTable.inventUnitId());
            select firstonly  unitOfMeasureConversion
               where      unitOfMeasureConversion.Product           == inventTable.Product
               &&         unitOfMeasureConversion.FromUnitOfMeasure == fromUnitId;

            this.ETGAlternateUOM      = UnitOfMeasure::find(unitOfMeasureConversion.ToUnitOfMeasure).Symbol;
            this.ETGAlternateQuantity = this.Qty * unitOfMeasureConversion.Factor;
        }
    }

}

/// <summary>
/// This is the new method created for validating the line
/// which should have only single issue related record.
/// </summary>
/// <returns>boolean.</returns>
public boolean etgIssueReceiveUpdate()
{
    boolean ret = true;
    if(SalesParameters::find().ETGEnableCylinderTracking)
    {
        InventJournalTrans inventJournaltrans, inventJournaltransRecId;
        InventJournalTable  inventJournalTable = InventJournalTable::find(this.JournalId);
        InventJournalName   inventJournalName  = InventJournalName::find(inventJournalTable.JournalNameId);

        if(inventJournalName.ETGManualAdditionorDeletion == NoYes::Yes && this.ETGIssueReceive == ETGIssueReceive::Issue)
        {
            select count(RecId) from inventJournaltrans
            where inventJournaltrans.JournalId       == inventJournalTable.JournalId
            &&    inventJournaltrans.ETGIssueReceive == ETGIssueReceive::Issue;

            select firstonly RecId from inventJournaltransRecId
            where inventJournaltransRecId.JournalId       == inventJournalTable.JournalId
            &&    inventJournaltransRecId.ETGIssueReceive == ETGIssueReceive::Issue;

            if(this.ETGIssueReceive == ETGIssueReceive::Issue 
                && inventJournaltrans.RecId > 0 
                && inventJournaltransRecId.RecId != this.RecId)
            {
                ret = checkFailed("@ETG_New:Issueshouldnothavemorethanoneline");
            }
        }
    }
    return ret;
}

/// <summary>
/// This method is for validating qty field, if user selects issue it should have negative qty
/// if user selects receive, qty should be positive.
/// </summary>
public void etgQtyValidation()
{
    if(SalesParameters::find().ETGEnableCylinderTracking)
    {

        InventJournalTable  inventJournalTable    = InventJournalTable::find(this.JournalId);
        InventJournalName   inventJournalName     = InventJournalName::find(inventJournalTable.JournalNameId);

        if(inventJournalName.ETGManualAdditionorDeletion == NoYes::Yes)
        {
            if(this.ETGIssueReceive == ETGIssueReceive::Issue && this.Qty >= 0)
            {
                throw Error ("@ETG_New:QuantityforIssue");
            }

            else if(this.ETGIssueReceive == ETGIssueReceive::Receive && this.Qty <= 0 )
            {
                throw Error ("@ETG_New:QuantityforReceive");
            }
        }
    }
}

