/// <summary>
/// COC of standard method to add custom BatchId
/// </summary>
public void insert(NoYes _dropEstimated)
{
    InventDim inventDim;

    if(ETGCanadaParameters::find().EnableDefaultBatchNumber == NoYes::Yes)
    {
        if (this.JournalType == InventJournalType::Transfer)
        {
            if (this.ToInventDimId)
            {
                inventDim = InventDim::find(this.ToInventDimId);
            }
            inventDim.inventBatchId = InventTable::find(this.ItemId).ETGDefaultBatchNumber;

            this.ToInventDimId = InventDim::findOrCreate(inventDim).InventDimId;
        }
    }

    next insert(_dropEstimated);
}
